using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, string> ParseXmlConfig(string configPath)
    {
        Dictionary<string, string> settings = new Dictionary<string, string>();
        XmlDocument xmlDocument = new XmlDocument();

        XmlReaderSettings xmlReaderSettings = new XmlReaderSettings();
        xmlReaderSettings.ProhibitDtd = false; // Allow DTD
        xmlReaderSettings.ValidationType = ValidationType.DTD;
        
        using (XmlReader xmlReader = XmlReader.Create(configPath, xmlReaderSettings))
        {
            xmlDocument.Load(xmlReader);
        }

        foreach(XmlNode node in xmlDocument.DocumentElement)
        {
            string key = node.Name;
            string value = node.InnerText;
            settings.Add(key, value);
        }
       
        return settings;
    }
}